[components-overlay-drawer-index] Drawer > Usage > Detail-row inspection

Drawer — Component for showing additional content alongside the main page.

The user's task here is "scan rows, drill into one." Keeping the list visible preserves orientation, while routing away breaks the rhythm.

Click a row in a table or list and a drawer slides in showing the record's full details. Fields are read-only or support small inline edits (a status toggle, a quick rename, picking a value from a list), and the user can move on to the next row without losing the table view.

```tsx title="drawer-secondary-details"
import {
  Button,
  Drawer,
  Inline,
  Stack,
  Table,
  Text,
} from '@marigold/components';
import type { DrawerProps } from '@marigold/components';

type Ticket = {
  id: string;
  subject: string;
  priority: 'High' | 'Medium' | 'Low';
  status: 'Open' | 'In Progress' | 'Resolved';
  assignee: string;
  created: string;
  updated: string;
  description: string;
  customerNote: string;
};

const tickets: Ticket[] = [
  {
    id: '4521',
    subject: 'Login issue',
    priority: 'High',
    status: 'Open',
    assignee: 'Jane Doe',
    created: 'Sep 12, 2025',
    updated: 'Sep 15, 2025',
    description:
      'User reports being unable to log in after the latest update. Error: "Invalid session token."',
    customerNote: '"I tried resetting my password, but I’m still locked out."',
  },
  {
    id: '4520',
    subject: 'Email notifications not sent',
    priority: 'Medium',
    status: 'In Progress',
    assignee: 'Marco Lee',
    created: 'Sep 11, 2025',
    updated: 'Sep 14, 2025',
    description:
      'Order confirmation emails are not arriving for customers using gmail.com addresses.',
    customerNote: '"Two of my recent orders never came through to my inbox."',
  },
  {
    id: '4519',
    subject: 'Dashboard loading slowly',
    priority: 'Low',
    status: 'Open',
    assignee: 'Priya Singh',
    created: 'Sep 10, 2025',
    updated: 'Sep 12, 2025',
    description:
      'Dashboard takes 8–10 seconds to load on first visit. Subsequent loads are normal.',
    customerNote: '"It used to be much faster a few weeks ago."',
  },
];

const TicketDrawer = ({
  ticket,
  ...props
}: { ticket: Ticket } & DrawerProps) => (
  <Drawer.Trigger>
    <Button variant="secondary" size="small">
      View
    </Button>
    <Drawer {...props} size="medium">
      <Drawer.Title>
        Ticket #{ticket.id} – {ticket.subject}
      </Drawer.Title>
      <Drawer.Content>
